INSERT INTO reviews (id, user_id, movie_id, review_text, rating, created_at) VALUES ('f45a82c4-8b20-4211-a965-48fffa01c80d', '22222222-2222-2222-2222-222222222222', 'dddddddd-dddd-dddd-dddd-dddddddddddd', 'Heath Ledger''s Joker is legendary.', 5.0, '2026-05-13 16:18:50.977368');
INSERT INTO reviews (id, user_id, movie_id, review_text, rating, created_at) VALUES ('4ac35567-20f3-4375-baa2-75c6c43e8ae8', '33333333-3333-3333-3333-333333333333', 'eeeeeeee-eeee-eeee-eeee-eeeeeeeeeeee', 'Mind-bending, complex, and rewarding.', 4.0, '2026-05-13 16:18:50.977368');
INSERT INTO reviews (id, user_id, movie_id, review_text, rating, created_at) VALUES ('f1dc9e7c-402c-4d2b-b6b1-1172ba9fdd22', '44444444-4444-4444-4444-444444444444', 'ffffffff-ffff-ffff-ffff-ffffffffffff', 'A biting social commentary wrapped in a thriller.', 5.0, '2026-05-13 16:18:50.977368');
